import anthropic
import asyncio

client = anthropic.Anthropic()

async def run_agent_with_gates(user_message: str):
    messages = [{"role": "user", "content": user_message}]

    while True:
        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=4096,
            tools=TOOL_SCHEMAS,
            messages=messages,
        )

        if response.stop_reason == "end_turn":
            return response.content

        # Process tool calls with gate interception
        tool_results = []
        for block in response.content:
            if block.type != "tool_use":
                continue
            try:
                result = await approval_gate(
                    tool=block.name,
                    args=block.input,
                    tool_fn=TOOL_REGISTRY[block.name],
                    notify_reviewer=send_slack_approval_request,
                )
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": str(result),
                })
            except (PermissionError, TimeoutError) as e:
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": f"[GATE BLOCKED] {e}",
                    "is_error": True,
                })

        messages.append({"role": "assistant", "content": response.content})
        messages.append({"role": "user", "content": tool_results})
